// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_R 1000
#define MAX_C 1000

// Structure to represent a cell in the maze
typedef struct {
    int r, c;
} Cell;

// Function to perform BFS
void bfs(char maze[MAX_R][MAX_C], int R, int C, Cell start, Cell end) {
    // Create a queue to hold the cells to be visited
    Cell queue[MAX_R * MAX_C];
    int front = 0, rear = 0;
    queue[rear++] = start;

    // Create a 2D array to keep track of visited cells
    int visited[MAX_R][MAX_C] = {{0}};
    visited[start.r][start.c] = 1;

    // Create a 2D array to store the parent of each cell
    Cell parent[MAX_R][MAX_C];

    // Perform BFS
    while (front < rear) {
        Cell current = queue[front++];
        if (current.r == end.r && current.c == end.c) {
            // If we reach the end, construct the path and print it
            printf("YES\n");
            while (current.r != start.r || current.c != start.c) {
                maze[current.r][current.c] = 'x';
                current = parent[current.r][current.c];
            }
            for (int i = 0; i < R; i++) {
                printf("%s\n", maze[i]);
            }
            return;
        }

        // Explore all possible directions from the current cell
        int dr[] = {-1, 1, 0, 0};
        int dc[] = {0, 0, -1, 1};
        for (int i = 0; i < 4; i++) {
            int nr = current.r + dr[i];
            int nc = current.c + dc[i];

            // Check if the new cell is within the maze boundaries
            if (nr < 0 || nr >= R || nc < 0 || nc >= C) {
                continue;
            }

            // Check if the new cell is a wall or has been visited before
            if (maze[nr][nc] == '#' || visited[nr][nc]) {
                continue;
            }

            // Mark the new cell as visited and add it to the queue
            visited[nr][nc] = 1;
            queue[rear++] = (Cell){nr, nc};
            parent[nr][nc] = current;
        }
    }

    // If we reach this point, it means there is no path from the start to the end
    printf("NO\n");
}

int main() {
    int R, C;
    scanf("%d %d", &R, &C);

    // Read the maze
    char maze[MAX_R][MAX_C];
    for (int i = 0; i < R; i++) {
        scanf("%s", maze[i]);
    }

    // Find the start and end positions
    Cell start, end;
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (maze[i][j] == 'M') {
                start = (Cell){i, j};
            } else if (maze[i][j] == 'D') {
                end = (Cell){i, j};
            }
        }
    }

    // Perform BFS
    bfs(maze, R, C, start, end);

    return 0;
}

