    static class Cell {
        int r, c;
        Cell(int r, int c) {
            this.r = r;
            this.c = c;
        }
    }

    // Function to perform BFS
    public static void bfs(char[][] maze, int R, int C, Cell start, Cell end) {
        // Create a queue to hold the cells to be visited
        Queue<Cell> q = new LinkedList<>();
        q.add(start);

        // Create a 2D array to keep track of visited cells
        boolean[][] visited = new boolean[R][C];
        visited[start.r][start.c] = true;

        // Create a 2D array to store the parent of each cell
        Cell[][] parent = new Cell[R][C];

        // Perform BFS
        while (!q.isEmpty()) {
            Cell current = q.poll();
            if (current.r == end.r && current.c == end.c) {
                // If we reach the end, construct the path and print it
                System.out.println("YES");
                while (current.r != start.r || current.c != start.c) {
                    maze[current.r][current.c] = 'x';
                    current = parent[current.r][current.c];
                }
                for (int i = 0; i < R; i++) {
                    System.out.println(new String(maze[i]));
                }
                return;
            }

            // Explore all possible directions from the current cell
            int dr[] = {-1, 1, 0, 0};
            int dc[] = {0, 0, -1, 1};
            for (int i = 0; i < 4; i++) {
                int nr = current.r + dr[i];
                int nc = current.c + dc[i];

                // Check if the new cell is within the maze boundaries
                if (nr < 0 || nr >= R || nc < 0 || nc >= C) {
                    continue;
                }

                // Check if the new cell is a wall or has been visited before
                if (maze[nr][nc] == '#' || visited[nr][nc]) {
                    continue;
                }

                // Mark the new cell as visited and add it to the queue
                visited[nr][nc] = true;
                q.add(new Cell(nr, nc));
                parent[nr][nc] = current;
            }
        }

        // If we reach this point, it means there is no path from the start to the end
        System.out.println("NO");
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int R = sc.nextInt();
        int C = sc.nextInt();
        sc.nextLine();

        // Read the maze
        char[][] maze = new char[R][C];
        for (int i = 0; i < R; i++) {
            maze[i] = sc.nextLine().toCharArray();
